const input = $('Called by Agent').first().json;
try {
  const raw = $input.first().json.content[0].text;
  const cleaned = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const response = JSON.parse(cleaned);
  return [{ json: {
    status: 'completed',
    workflow: '07_review_responder',
    platform: input.platform || input.parameters?.platform || 'google',
    rating: input.rating || input.parameters?.rating || 5,
    reviewer_name: input.reviewer_name || input.parameters?.reviewer_name || 'Customer',
    review_text: input.review_text || input.parameters?.review_text || input.chatInput || 'Great service!',
    response_text: response.response_text,
    tone: response.tone,
    follow_up_action: response.follow_up_action,
    priority: response.priority,
    completedAt: new Date().toISOString()
  } }];
} catch (e) {
  const raw = $input.first().json.content?.[0]?.text || 'No content';
  return [{ json: {
    status: 'completed',
    workflow: '07_review_responder',
    content_raw: raw,
    parse_note: 'Response was not valid JSON, returning raw text',
    completedAt: new Date().toISOString()
  } }];
}
